const { Client, GatewayIntentBits } = require('discord.js');
const client = new Client({
  intents: [
    GatewayIntentBits.Guilds,
    GatewayIntentBits.GuildMembers,
    GatewayIntentBits.GuildMessages,
    GatewayIntentBits.GuildBans,
  ],
});

client.commands = new Map();

client.commands.set('ban', {
  name: 'ban',
  description: 'Bans a member from the server',
  options: [
    {
      name: 'member',
      description: 'The member to ban',
      type: 'user',
      required: true,
    },
  ],
  execute: async (interaction) => {
    const member = interaction.options.getUser('member');
    const guild = interaction.guild;
    await guild.members.ban(member, { days: 7, reason: 'Banned by the bot' });
    await interaction.reply(`Banned ${member.tag} from the server.`);
  },
});

client.login('YOUR_BOT_TOKEN');

// Replace 'YOUR_BOT_TOKEN' with your bot's token from the Discord Developer Portal.
```

Here's how the code works:

*   We create a new instance of the `Client` class from the `discord.js` library, specifying the intents we need (`GatewayIntentBits.Guilds`, `GatewayIntentBits.GuildMembers`, `GatewayIntentBits.GuildMessages`, and `GatewayIntentBits.GuildBans`).
*   We define a map called `client.commands` to store our commands.
*   We add a command called `ban` to the map, specifying its name, description, and options (in this case, a single option for the member to ban).
*   The `execute` function is called when the command is invoked. It gets the member to ban from the options, bans the member using the `guild.members.ban()` method, and replies to the interaction with a success message.
*   Finally, we log in to the bot using the `login()` method, replacing `'YOUR_BOT_TOKEN'` with your bot's token from the Discord Developer Portal.

