#include <stdlib.h>

// Define some constants
#define WIDTH 640
#define HEIGHT 480
#define BLOCK_SIZE 20
#define SNAKE_SPEED 10

// Define some colors
#define BLACK 0x000000
#define WHITE 0xFFFFFF
#define GREEN 0x008000

// Define the snake structure
typedef struct {
    int x, y;
    int dir_x, dir_y;
} Snake;

// Define the food structure
