void update_snake(Snake* snake);
void draw_snake(Snake* snake, SDL_Renderer* renderer);
void handle_events(Snake* snake, SDL_Event* event);
void check_collision(Snake* snake, Food* food);

int main(int argc, char* argv[]) {
    // Initialize SDL
    SDL_Init(SDL_INIT_VIDEO);
    SDL_Window* window = SDL_CreateWindow("Snake Game", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, WIDTH, HEIGHT, SDL_WINDOW_SHOWN);
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    // Initialize snake and food
    Snake snake;
    Food food;

    // Initialize snake
    init_snake(&snake);

    // Main game loop
    while (1) {
        // Handle events
        SDL_Event event;
        while (SDL_PollEvent(&event)) {
            handle_events(&snake, &event);
        }

        // Update snake
        update_snake(&snake);

        // Check collision
        check_collision(&snake, &food);

        // Draw everything
        SDL_SetRenderDrawColor(renderer, BLACK, BLACK, BLACK, 255);
        SDL_RenderClear(renderer);
        draw_snake(&snake, renderer);
        SDL_Rect food_rect = {food.x * BLOCK_SIZE, food.y * BLOCK_SIZE, BLOCK_SIZE, BLOCK_SIZE};
        SDL_SetRenderDrawColor(renderer, GREEN, GREEN, GREEN, 255);
        SDL_RenderFillRect(renderer, &food_rect);
        SDL_RenderPresent(renderer);

        // Cap frame rate
        SDL_Delay(1000 / SNAKE_SPEED);
    }

    // Clean up
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();
    return 0;
}

void init_snake(Snake* snake) {
    snake->x = WIDTH / 2;
    snake->y = HEIGHT / 2;
    snake->dir_x = 1;
    snake->dir_y = 0;
}

void update_snake(Snake* snake) {
    snake->x += snake->dir_x * BLOCK_SIZE;
    snake->y += snake->dir_y * BLOCK_SIZE;
}

void draw_snake(Snake* snake, SDL_Renderer* renderer) {
    SDL_Rect snake_rect = {snake->x, snake->y, BLOCK_SIZE, BLOCK_SIZE};
    SDL_SetRenderDrawColor(renderer, WHITE, WHITE, WHITE, 255);
    SDL_RenderFillRect(renderer, &snake_rect);
}

void handle_events(Snake* snake, SDL_Event* event) {
    if (event->type == SDL_KEYDOWN) {
        switch (event->key.keysym.sym) {
            case SDLK_LEFT:
                snake->dir_x = -1;
                snake->dir_y = 0;
                break;
            case SDLK_RIGHT:
                snake->dir_x = 1;
                snake->dir_y = 0;
                break;
            case SDLK_UP:
                snake->dir_x = 0;
                snake->dir_y = -1;
                break;
            case SDLK_DOWN:
                snake->dir_x = 0;
                snake->dir_y = 1;
                break;
        }
    }
}

